class DSU(n: Int) {
    val parent = Array.fill(n)(0)
    // diff[i]: parity of the path weight from node i to parent[i]
    val diff = Array.fill(n)(0) 

    init() {
        for (i <- 0 until n) {
            parent(i) = i
        }
    }

    // Returns (root, parity_to_root). Parity is 0 or 1.
    def find(i: Int): (Int, Int) = {
        if (parent(i) == i) {
            (i, 0)
        } else {
            val (root, p_p) = find(parent(i))

            // Update path compression: i -> root = i -> parent(i) -> root
            val new_d_i = (diff(i) + p_p) % 2
            parent(i) = root
            diff(i) = new_d_i

            (root, new_d_i)
        }
    }

    // Attempts to union components of u and v using edge weight w.
    // Returns true if the edge is added (valid), false otherwise.
    def tryUnion(u: Int, v: Int, w: Int): Boolean = {
        val (rootU, pU) = find(u)
        val (rootV, pV) = find(v)

        if (rootU != rootV) {
            // Case 1: Different components. Merge V into U.
            parent(rootV) = rootU

            // Calculate diff[rootV]: parity of path rootV -> rootU
            // Path parity = pV + w + pU (mod 2)
            val new_d_rv = (pV + w + pU) % 2
            diff(rootV) = new_d_rv

            true // Edge added
        } else {
            // Case 2: Same component. Check cycle parity.

            // Cycle weight parity = (pU + pV + w) % 2
            val cycle_parity = (pU + pV + w) % 2

            if (cycle_parity == 0) {
                true // Edge added (cycle is even)
            } else {
                false // Edge rejected (cycle is odd)
            }
        }
    }
}

